/**
 * Service để tính toán cảnh báo dựa trên ngưỡng môi trường
 */

const toNumber = (value) => {
	const parsed = Number(value)
	return Number.isFinite(parsed) ? parsed : null
}

const getMetricStatus = (current, minValue, maxValue) => {
	if (current == null) return 'no-data'
	if (minValue != null && current < minValue) return 'low'
	if (maxValue != null && current > maxValue) return 'high'
	return 'ok'
}

const metricConfig = {
	ph: { label: 'Độ pH', unit: 'pH', precision: 1 },
	temperature: { label: 'Nhiệt độ nước', unit: '°C', precision: 1 },
	salinity: { label: 'Độ mặn', unit: 'ppt', precision: 1 },
	oxygen: { label: 'Oxy hòa tan (DO)', unit: 'mg/L', precision: 1 },
	turbidity: { label: 'Độ đục', unit: 'NTU', precision: 1 },
}

const metricKeys = {
	ph: { minKey: 'min_ph', maxKey: 'max_ph', valueKey: 'ph' },
	temperature: { minKey: 'min_temp', maxKey: 'max_temp', valueKey: 'temperature' },
	salinity: { minKey: 'min_salinity', maxKey: 'max_salinity', valueKey: 'salinity' },
	oxygen: { minKey: 'min_oxygen', maxKey: 'max_oxygen', valueKey: 'oxygen' },
	turbidity: { minKey: 'min_turbidity', maxKey: 'max_turbidity', valueKey: 'turbidity' },
}

/**
 * Xây dựng danh sách cảnh báo từ dữ liệu realtime và ngưỡng
 * @param {Object} realtimeData - Dữ liệu realtime từ cảm biến
 * @param {Object} thresholds - Dữ liệu ngưỡng từ cơ sở dữ liệu
 * @param {Object} pond - Thông tin ao
 * @returns {Array} Danh sách cảnh báo
 */
export const buildThresholdAlerts = (realtimeData, thresholds, pond) => {
	if (!realtimeData || !thresholds || !pond) {
		return []
	}

	const alerts = []

	Object.entries(metricKeys).forEach(([metricCode, keys]) => {
		const config = metricConfig[metricCode]
		const value = toNumber(realtimeData[keys.valueKey])
		const minValue = toNumber(thresholds[keys.minKey])
		const maxValue = toNumber(thresholds[keys.maxKey])

		// Chỉ tạo cảnh báo nếu có giá trị realtime và cấu hình ngưỡng
		if (value == null || (minValue == null && maxValue == null)) {
			return
		}

		const status = getMetricStatus(value, minValue, maxValue)

		if (status === 'low' || status === 'high') {
			const direction = status === 'high' ? 'vượt ngưỡng tối đa' : 'thấp hơn ngưỡng tối thiểu'
			const thresholdValue = status === 'high' ? maxValue : minValue
			const severity = status === 'high' ? 'high' : 'low'

			alerts.push({
				key: `${pond.pond_id}-${metricCode}-${status}`,
				pondId: pond.pond_id,
				pondCode: pond.pond_code,
				pondName: pond.pond_name,
				metricCode,
				metricLabel: config.label,
				value,
				unit: config.unit,
				thresholdValue,
				severity,
				direction,
				title: `${config.label} ${direction} ở ${pond.pond_code}`,
				description: `Giá trị hiện tại ${value.toFixed(config.precision)} ${config.unit} ${direction} so với ngưỡng ${thresholdValue.toFixed(config.precision)} ${config.unit}`,
				timestamp: new Date().toISOString(),
			})
		}
	})

	return alerts
}

/**
 * Tính toán cảnh báo cho tất cả các ao
 * @param {Array} ponds - Danh sách ao
 * @param {Object} realtimeSensorData - Dữ liệu realtime từ context
 * @param {Object} thresholdsMap - Map of pondId -> thresholds
 * @returns {Array} Danh sách tất cả cảnh báo
 */
export const buildAllThresholdAlerts = (ponds, realtimeSensorData, thresholdsMap) => {
	if (!ponds || !Array.isArray(ponds) || !realtimeSensorData || !thresholdsMap) {
		return []
	}

	return ponds
		.flatMap((pond) => {
			const pondId = String(pond.pond_id)
			const pondRealtime = realtimeSensorData[pondId] || {}
			const thresholds = thresholdsMap[pondId]

			if (!thresholds) {
				return []
			}

			return buildThresholdAlerts(pondRealtime, thresholds, pond)
		})
		.sort((a, b) => {
			// Ưu tiên cảnh báo mới nhất
			if (a.severity !== b.severity) {
				return a.severity === 'high' ? -1 : 1
			}
			return new Date(b.timestamp) - new Date(a.timestamp)
		})
}

/**
 * Lấy tóm tắt cảnh báo theo mức độ
 * @param {Array} alerts - Danh sách cảnh báo
 * @returns {Object} Tóm tắt theo severity
 */
export const summarizeAlerts = (alerts) => {
	return {
		total: alerts.length,
		critical: alerts.filter((a) => a.severity === 'high').length,
		warning: alerts.filter((a) => a.severity === 'low').length,
		bySeverity: {
			high: alerts.filter((a) => a.severity === 'high'),
			low: alerts.filter((a) => a.severity === 'low'),
		},
	}
}

export default {
	buildThresholdAlerts,
	buildAllThresholdAlerts,
	summarizeAlerts,
}
